import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';  // Import useNavigate hook
import { FaHome, FaComments, FaCog, FaSignOutAlt } from 'react-icons/fa'; // Icons for navigation
import './SideNav.css';  // Import the styles for the side navigation

function SideNav({ logout }) {
  const [isOpen, setIsOpen] = useState(false); // State to control whether the sidebar is open or not
  const navigate = useNavigate(); // Initialize the navigate function

  const toggleNav = () => {
    setIsOpen(!isOpen); // Toggle the side navigation visibility
  };

  // Handler functions for navigation
  const goToHome = () => navigate('/HomePage');
  const goToChat = () => navigate('/ChatBox');
  const goToSettings = () => navigate('/Settings');

  return (
    <div className={`side-nav-container ${isOpen ? 'open' : ''}`}>
      {/* Side Navigation - Visible when 'isOpen' is true */}
      <div className={`side-nav ${isOpen ? 'open' : ''}`}>
        <ul>
          <li>
            <button onClick={goToHome} aria-label="Go to Home">
              <FaHome /> Home
            </button>
          </li>
          <li>
            <button onClick={goToChat} aria-label="Go to Chat">
              <FaComments /> Chat
            </button>
          </li>
          <li>
            <button onClick={goToSettings} aria-label="Go to Settings">
              <FaCog /> Settings
            </button>
          </li>
          <li>
            <button onClick={logout} aria-label="Logout">
              <FaSignOutAlt /> Logout
            </button>
          </li>
        </ul>
      </div>

      {/* Arrow button */}
      <div className={`arrow ${isOpen ? 'rotate' : ''}`} onClick={toggleNav} aria-label="Toggle navigation">
        &#x2192; {/* Rightwards arrow */}
      </div>
    </div>
  );
}

export default SideNav;
